/*
======================================================================
Design System & Global Styles
----------------------------------------------------------------------
This CSS aims to closely match the provided church site design:
- Flat, content-first layout
- Minimalist styling with clear typographic hierarchy
- Large photographic header image
- Traditional, utility-focused navigation
======================================================================
*/

:root {
    /* Color Palette -------------------------------------------------- */
    --color-primary-green: #6CB33F;
    --color-primary-dark: #333333;

    --color-secondary-light: #E5E5E5;
    --color-secondary-mid: #CCCCCC;

    --color-accent-orange: #FF6600;
    --color-accent-soft: #FFD54F;

    --color-neutral-white: #FFFFFF;
    --color-neutral-bg: #F7F7F7;
    --color-neutral-text: #777777;

    --color-border-light: #E5E5E5;
    --color-border-mid: #CCCCCC;

    --color-success: #6CB33F;
    --color-error: #CC3333;
    --color-warning: #FFCC00;
    --color-info: #337AB7;

    /* Typography ----------------------------------------------------- */
    --font-heading: "Libre Franklin", Helvetica, Arial, sans-serif;
    --font-body: "Source Sans 3", Arial, sans-serif;
    --font-code: "Source Code Pro", monospace;

    --font-size-h1: 32px;
    --font-size-h2: 26px;
    --font-size-h3: 20px;
    --font-size-body: 16px;
    --font-size-small: 13px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.7;

    /* Spacing Scale (based on 8px) ---------------------------------- */
    --space-0: 0;
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 16px;
    --space-4: 24px;
    --space-5: 32px;
    --space-6: 48px;
    --space-7: 64px;

    /* Layout --------------------------------------------------------- */
    --layout-max-width: 1100px;
    --header-nav-height: 56px;
}

/* Global Reset-ish --------------------------------------------------- */
* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-relaxed);
    color: var(--color-primary-dark);
    background-color: var(--color-neutral-white);
}

img {
    max-width: 100%;
    height: auto;
    border: 0;
}

a {
    color: var(--color-info);
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: underline;
}

p {
    margin-top: 0;
    margin-bottom: var(--space-3);
}

h1,
h2,
h3,
h4,
h5,
h6 {
    font-family: var(--font-heading);
    font-weight: var(--font-weight-regular);
    line-height: var(--line-height-tight);
    margin-top: 0;
    margin-bottom: var(--space-3);
    color: var(--color-primary-dark);
}

h1 { font-size: var(--font-size-h1); }

h2 { font-size: var(--font-size-h2); }

h3 { font-size: var(--font-size-h3); }

small,
.text-small {
    font-size: var(--font-size-small);
}

code,
pre {
    font-family: var(--font-code);
}

/* Layout Utility ----------------------------------------------------- */
.container {
    max-width: var(--layout-max-width);
    margin-left: auto;
    margin-right: auto;
    padding-left: var(--space-3);
    padding-right: var(--space-3);
}

/* Header & Global Navigation ---------------------------------------- */
.site-header {
    background-color: var(--color-neutral-white);
}

.top-bar {
    border-bottom: 1px solid var(--color-border-light);
}

.top-bar-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    min-height: var(--header-nav-height);
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
}

.site-branding {
    display: flex;
    align-items: center;
    flex: 1 1 auto;
}

.logo-link {
    display: inline-flex;
    align-items: center;
    color: var(--color-primary-dark);
    text-decoration: none;
}

.logo-image {
    max-height: 70px; /* matches visual proportion of logo in screenshot */
    margin-right: var(--space-2);
}

.site-title-group {
    display: inline-flex;
    flex-direction: column;
}

.site-title {
    font-family: var(--font-heading);
    font-weight: var(--font-weight-semibold);
    font-size: 18px;
    line-height: var(--line-height-tight);
}

.site-tagline {
    font-size: var(--font-size-small);
    color: var(--color-neutral-text);
    margin-top: var(--space-1);
}

.primary-nav {
    flex: 0 1 auto;
}

.primary-nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    align-items: center;
    gap: 24px; /* visual spacing between menu items */
    font-family: var(--font-heading);
    font-size: 15px;
}

.primary-nav-item {
    position: relative;
}

.primary-nav-item a {
    color: var(--color-primary-dark);
    text-decoration: none;
    padding-top: 6px;
    padding-bottom: 6px;
    border-bottom: 2px solid transparent;
}

.primary-nav-item a:hover,
.primary-nav-item a:focus {
    color: var(--color-primary-green);
    border-bottom-color: var(--color-primary-green);
}

/* Active state helper (to be applied per page via server-side logic) */
.primary-nav-item.is-active a {
    color: var(--color-primary-green);
    border-bottom-color: var(--color-primary-green);
}

/* Hero Banner -------------------------------------------------------- */
.hero-banner {
    width: 100%;
    height: 260px; /* approximate height from screenshot */
    background-image: url("assets/hero-church.jpg"); /* replace with actual hero image path */
    background-size: cover;
    background-position: center center;
    background-repeat: no-repeat;
}

/* Main Content Area -------------------------------------------------- */
.site-main {
    padding-top: var(--space-5);
    padding-bottom: var(--space-6);
}

/* Optional two-column layout styles (for pages that add a sidebar)
   These match the visual style of the left-hand sidebar in the design
   but are not instantiated in this base framework. ------------------- */
.layout-with-sidebar {
    display: grid;
    grid-template-columns: 260px minmax(0, 1fr);
    column-gap: var(--space-5);
}

.side-nav {
    list-style: none;
    margin: 0;
    padding: 0;
    border-top: 1px solid var(--color-secondary-mid);
}

.side-nav-item {
    border-bottom: 1px solid var(--color-secondary-mid);
}

.side-nav-item a {
    display: block;
    padding: 12px var(--space-2);
    font-family: var(--font-body);
    font-size: 15px;
    color: var(--color-primary-dark);
    text-decoration: none;
}

.side-nav-item a:hover,
.side-nav-item a:focus {
    background-color: var(--color-neutral-bg);
}

.side-nav-item.is-active a {
    background-color: var(--color-secondary-light);
    color: var(--color-primary-green);
}

/* RSS badge style (for content areas, not used in framework HTML) --- */
.badge-rss {
    display: inline-block;
    padding: 2px 4px;
    font-size: 11px;
    font-family: var(--font-heading);
    font-weight: var(--font-weight-semibold);
    background-color: var(--color-accent-orange);
    color: #fff;
    text-transform: uppercase;
}

/* Footer ------------------------------------------------------------- */
.site-footer {
    background-color: var(--color-neutral-bg);
    border-top: 1px solid var(--color-border-mid);
    margin-top: auto;
}

.footer-inner {
    padding-top: var(--space-4);
    padding-bottom: var(--space-5);
}

.footer-links-block {
    margin-bottom: var(--space-3);
}

.footer-heading {
    font-size: 15px;
    font-weight: var(--font-weight-semibold);
    text-transform: none;
    margin-bottom: var(--space-2);
    color: var(--color-primary-dark);
}

.footer-nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    flex-wrap: wrap;
    gap: 8px 24px; /* relatively loose link spacing similar to header */
}

.footer-nav-item a {
    font-size: var(--font-size-small);
    color: var(--color-primary-dark);
    text-decoration: none;
}

.footer-nav-item a:hover,
.footer-nav-item a:focus {
    text-decoration: underline;
    color: var(--color-primary-green);
}

.footer-meta {
    margin-top: var(--space-3);
}

.footer-copy {
    font-size: var(--font-size-small);
    color: var(--color-neutral-text);
    margin: 0;
}

/* Buttons (for future forms, consistent with flat design) ------------ */
.btn {
    display: inline-block;
    padding: 8px 16px;
    font-family: var(--font-heading);
    font-size: 15px;
    font-weight: var(--font-weight-medium);
    border-radius: 2px;
    border: 1px solid var(--color-secondary-mid);
    background-color: var(--color-secondary-light);
    color: var(--color-primary-dark);
    text-align: center;
    cursor: pointer;
}

.btn-primary {
    background-color: var(--color-primary-green);
    border-color: #5a9b34;
    color: #fff;
}

.btn:hover,
.btn:focus {
    filter: brightness(0.96);
    text-decoration: none;
}

/* Form elements (for future use) ------------------------------------ */
.form-group {
    margin-bottom: var(--space-3);
}

.form-group label {
    display: block;
    margin-bottom: var(--space-1);
    font-size: 14px;
}

.form-control {
    display: block;
    width: 100%;
    padding: 8px 10px;
    font-size: var(--font-size-body);
    font-family: var(--font-body);
    border-radius: 2px;
    border: 1px solid var(--color-secondary-mid);
    background-color: var(--color-neutral-white);
}

.form-control:focus {
    outline: none;
    border-color: var(--color-primary-green);
}

.form-help {
    margin-top: 4px;
    font-size: var(--font-size-small);
    color: var(--color-neutral-text);
}

.form-error {
    margin-top: 4px;
    font-size: var(--font-size-small);
    color: var(--color-error);
}

/* Responsive Adjustments -------------------------------------------- */
@media (max-width: 900px) {
    .top-bar-inner {
        flex-direction: column;
        align-items: flex-start;
        gap: var(--space-2);
    }

    .primary-nav-list {
        flex-wrap: wrap;
        row-gap: var(--space-1);
        column-gap: 16px;
    }

    .layout-with-sidebar {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 600px) {
    .hero-banner {
        height: 200px;
    }

    .site-tagline {
        display: none; /* reduces clutter on very small screens */
    }

    .footer-nav-list {
        flex-direction: column;
        gap: 4px;
    }
}
